+    fn try_build_live_vtab_direct_projection(
+        table_width: usize,
+        source_targets: &[Option<usize>],
+    ) -> Option<DirectLiveVtabInsertProjection> {
+        let mut explicit_rowid_source = None;
+        let mut value_sources = vec![None; table_width];
+
+        for (source_idx, target_idx) in source_targets.iter().copied().enumerate() {
+            if let Some(target_idx) = target_idx {
+                let source_slot = value_sources.get_mut(target_idx)?;
+                if source_slot.is_some() {
+                    return None;
+                }
+                *source_slot = Some(source_idx);
+            } else if explicit_rowid_source.replace(source_idx).is_some() {
+                return None;
+            }
+        }
+
