+    #[test]
+    fn test_live_vtab_insert_layout_enables_direct_projection_for_full_unique_mapping() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE VIRTUAL TABLE docs USING fts5(subject, body)")
+            .unwrap();
+
+        let statement = conn
+            .cached_parse_single(
+                "INSERT INTO docs(rowid, subject, body) SELECT 7, 'Hello', 'Rust world';",
+            )
+            .unwrap();
+        let Statement::Insert(insert_stmt) = statement.as_ref() else {
+            panic!("expected INSERT statement");
+        };
+
+        let layout = conn.resolve_live_vtab_insert_layout(insert_stmt).unwrap();
+        let direct_projection = layout
+            .direct_projection
+            .as_ref()
+            .expect("expected direct projection for unique full-width mapping");
+        assert_eq!(direct_projection.explicit_rowid_source, Some(0));
+        assert_eq!(direct_projection.value_sources, vec![1, 2]);
+
+        let row = conn
+            .build_live_vtab_insert_row(
+                &layout,
+                &[
+                    SqliteValue::Integer(7),
+                    SqliteValue::Text("Hello".into()),
+                    SqliteValue::Text("Rust world".into()),
+                ],
+                "test direct projection row",
+            )
+            .unwrap();
+        assert_eq!(row.explicit_rowid, Some(SqliteValue::Integer(7)));
+        assert_eq!(
+            row.values,
+            vec![
+                SqliteValue::Text("Hello".into()),
+                SqliteValue::Text("Rust world".into()),
+            ],
+        );
+    }
